package com.example.demo.ui;import com.example.demo.dto.EmpleadoDTO;import com.example.demo.models.PermisoUsuario;import com.example.demo.services.EmpleadoService;import com.vaadin.flow.component.button.*;import com.vaadin.flow.component.checkbox.CheckboxGroup;import com.vaadin.flow.component.dialog.Dialog;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.*;import com.vaadin.flow.component.textfield.*;import com.vaadin.flow.component.datepicker.DatePicker;import com.vaadin.flow.router.*;import java.util.*;
@Route(value="empleados",layout=MainLayout.class)@PageTitle("Empleados | Franco")public class EmpleadosView extends VerticalLayout{private final EmpleadoService service;private final Grid<EmpleadoDTO>grid=new Grid<>(EmpleadoDTO.class,false);public EmpleadosView(EmpleadoService service){this.service=service;addClassName("content-view");setSizeFull();grid.addColumn(e->e.nombre()+" "+e.apellido()).setHeader("Empleado");grid.addColumn(EmpleadoDTO::email).setHeader("Email");grid.addColumn(EmpleadoDTO::puesto).setHeader("Puesto");grid.addColumn(EmpleadoDTO::legajo).setHeader("Legajo");grid.addColumn(e->e.activo()?"Activo":"Inactivo").setHeader("Estado");grid.addComponentColumn(e->new Button("Ficha y permisos",x->form(e))).setHeader("Acciones");add(ViewSupport.header("Empleados"),grid);expand(grid);refresh();}private void refresh(){grid.setItems(service.listar());}private void form(EmpleadoDTO e){Dialog d=new Dialog();d.setHeaderTitle(e.nombre()+" "+e.apellido());d.setWidth("min(720px,95vw)");TextField file=new TextField("Legajo"),position=new TextField("Puesto"),emergency=new TextField("Teléfono de emergencia");DatePicker hired=new DatePicker("Fecha de contratación");BigDecimalField salary=new BigDecimalField("Sueldo de referencia");TextArea notes=new TextArea("Observaciones");CheckboxGroup<String>permissions=new CheckboxGroup<>("Permisos adicionales");permissions.setItems(Arrays.stream(PermisoUsuario.Permiso.values()).map(Enum::name).toList());set(file,e.legajo());set(position,e.puesto());set(emergency,e.telefonoEmergencia());hired.setValue(e.fechaContratacion());salary.setValue(e.sueldo());notes.setValue(e.observaciones()==null?"":e.observaciones());permissions.select(e.permisos());d.add(new VerticalLayout(new HorizontalLayout(file,position),new HorizontalLayout(hired,salary),emergency,notes,permissions));Button save=new Button("Guardar",x->{try{service.guardar(new EmpleadoDTO(e.usuarioId(),e.nombre(),e.apellido(),e.email(),e.rol(),e.activo(),file.getValue(),position.getValue(),hired.getValue(),salary.getValue(),emergency.getValue(),notes.getValue(),permissions.getSelectedItems()),UserSession.getUser().id());d.close();refresh();ViewSupport.success("Ficha actualizada");}catch(RuntimeException ex){ViewSupport.error(ex);}});save.addThemeVariants(ButtonVariant.LUMO_PRIMARY);d.getFooter().add(new Button("Cancelar",x->d.close()),save);d.open();}private void set(TextField f,String v){f.setValue(v==null?"":v);}}
